'use client'
import { useEffect, useRef } from 'react'
import styles from './Hero.module.css'

interface Props {
  title: string
  subtitle: string
}

export function Hero({ title, subtitle }: Props) {
  const surfaceRef = useRef<HTMLDivElement>(null)

  // Translate cursor position into a CSS variable so the gradient
  // appears to track the viewer. Throttled via rAF to one frame.
  useEffect(() => {
    let raf: number | null = null
    let pendingX = 50
    let pendingY = 50
    const surface = surfaceRef.current
    if (!surface) return
    const onMove = (e: PointerEvent) => {
      const rect = surface.getBoundingClientRect()
      pendingX = ((e.clientX - rect.left) / rect.width) * 100
      pendingY = ((e.clientY - rect.top) / rect.height) * 100
      if (raf == null) {
        raf = requestAnimationFrame(() => {
          surface.style.setProperty('--mx', `${pendingX}%`)
          surface.style.setProperty('--my', `${pendingY}%`)
          raf = null
        })
      }
    }
    window.addEventListener('pointermove', onMove, { passive: true })
    return () => {
      window.removeEventListener('pointermove', onMove)
      if (raf != null) cancelAnimationFrame(raf)
    }
  }, [])

  return (
    <section ref={surfaceRef} className={styles.hero}>
      <div className={styles.gradient} aria-hidden />
      <div className={styles.grain} aria-hidden />
      <div className={styles.content}>
        <h1 className={styles.title}>{title}</h1>
        <p className={styles.subtitle}>{subtitle}</p>
      </div>
    </section>
  )
}

.hero {
  position: relative;
  min-height: 100vh;
  display: grid;
  place-items: center;
  overflow: hidden;
  --mx: 50%;
  --my: 50%;
  --accent: oklch(72% 0.16 270);
}

.gradient {
  position: absolute;
  inset: -20%;
  background: conic-gradient(
    from 220deg at var(--mx) var(--my),
    color-mix(in oklch, var(--accent) 80%, transparent),
    oklch(15% 0.02 270),
    color-mix(in oklch, var(--accent) 40%, transparent),
    oklch(15% 0.02 270),
    color-mix(in oklch, var(--accent) 80%, transparent)
  );
  filter: blur(60px) saturate(140%);
  animation: rotate 60s linear infinite;
  will-change: transform;
}

@keyframes rotate {
  to { transform: rotate(360deg); }
}

.grain {
  position: absolute;
  inset: 0;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='180' height='180'><filter id='n'><feTurbulence baseFrequency='0.85' /></filter><rect width='100%' height='100%' filter='url(%23n)' opacity='0.22'/></svg>");
  mix-blend-mode: overlay;
  pointer-events: none;
}

.content {
  position: relative;
  text-align: center;
  padding: 0 1.5rem;
}

.title {
  font-size: clamp(3.5rem, 10vw, 8rem);
  font-weight: 500;
  letter-spacing: -0.04em;
  line-height: 0.95;
  background: linear-gradient(180deg, white, color-mix(in oklch, white 60%, transparent));
  -webkit-background-clip: text;
  color: transparent;
}

.subtitle {
  margin-top: 1.25rem;
  font-size: 1.125rem;
  color: color-mix(in oklch, white 70%, transparent);
}

@media (prefers-reduced-motion: reduce) {
  .gradient { animation: none; }
}
